<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Snake Game</title>
    <style>
        body {
            background-color: #1a1a1a;
            color: #ffffff;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }
        #game-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 15px;
        }
        #score {
            font-size: 2rem;
            font-weight: bold;
            color: #4caf50;
        }
        canvas#snake {
            background-color: #000000;
            border: 4px solid #333;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            display: block;
        }
        .controls {
            display: flex;
            gap: 10px;
        }
        button {
            padding: 10px 20px;
            font-size: 1rem;
            cursor: pointer;
            background-color: #333;
            color: white;
            border: none;
            border-radius: 4px;
            transition: background-color 0.2s, transform 0.1s;
        }
        button:hover {
            background-color: #444;
        }
        button:active {
            transform: scale(0.95);
        }
        #start { background-color: #2e7d32; }
        #pause { background-color: #c62828; }
        #reset { background-color: #1565c0; }
    </style>
</head>
<body>

<div id="game-container">
    <div id="score">Score: 0</div>
    <canvas id="snake" width="400" height="400"></canvas>
    <div class="controls">
        <button id="start">Start</button>
        <button id="pause">Pause</button>
        <button id="reset">Reset</button>
    </div>
</div>

<script>
(function() {
    const canvas = document.getElementById('snake');
    const ctx = canvas.getContext('2d');
    const scoreEl = document.getElementById('score');
    const startBtn = document.getElementById('start');
    const pauseBtn = document.getElementById('pause');
    const resetBtn = document.getElementById('reset');

    const gridSize = 20; // 20x20 cells
    const cellSize = canvas.width / gridSize;

    let gameLoopId = null;

    const game = {
        w: gridSize,
        h: gridSize,
        snakeBody: [],
        foodPos: [15, 15],
        scoreValue: 0,
        isAlive: false,
        currentDirection: 'right',
        nextDirection: 'right',

        reset() {
            this.snakeBody = [[5, 10], [4, 10], [3, 10]]; // Length 3
            this.foodPos = [15, 10];
            this.scoreValue = 0;
            this.isAlive = true;
            this.currentDirection = 'right';
            this.nextDirection = 'right';
            this.draw();
            updateScoreDisplay(this.scoreValue);
        },

        tick() {
            if (!this.isAlive) return;

            // Apply the queued direction
            this.currentDirection = this.nextDirection;

            const [headX, headY] = this.snakeBody[0];
            let dx = 0;
            let dy = 0;

            if (this.currentDirection === 'up') dy = -1;
            else if (this.currentDirection === 'down') dy = 1;
            else if (this.currentDirection === 'left') dx = -1;
            else if (this.currentDirection === 'right') dx = 1;

            const newHead = [headX + dx, headY + dy];

            // Wall collision check
            if (newHead[0] < 0 || newHead[0] >= this.w || newHead[1] < 0 || newHead[1] >= this.h) {
                this.isAlive = false;
                this.draw();
                return;
            }

            // Self collision check
            if (this.snakeBody.some(seg => seg[0] === newHead[0] && seg[1] === newHead[1])) {
                this.isAlive = false;
                this.draw();
                return;
            }

            // Move snake
            this.snakeBody.unshift(newHead);

            // Food collision check
            if (newHead[0] === this.foodPos[0] && newHead[1] === this.foodPos[1]) {
                this.scoreValue++;
                updateScoreDisplay(this.scoreValue);
                this.generateFood();
            } else {
                this.snakeBody.pop();
            }

            this.draw();
        },

        setDir(dir) {
            const opposites = { 'up': 'down', 'down': 'un', 'left': 'right', 'right': 'left' }; // dummy logic check
            // Corrected 180 reversal check:
            const isOpposite = (d) => {
                if (this.currentDirection === 'up' && d === 'down') return true;
                if (this.currentDirection === 'down' && d === 'up') return true;
                if (this.currentDirection === 'left' && d === 'right') return true;
                if (this.currentDirection === 'right' && d === 'left') return true;
                return false;
            };

            // Also check against nextDirection to prevent rapid 180 turns in one tick
            const isNextOpposite = (d) => {
                if (this.nextDirection === 'up' && d === 'down') return true;
                if (this.nextDirection === 'down' && d === 'up') return true;
                if (this.nextDirection === 'left' && d === 'right') return true;
                if (this.nextDirection === 'right' && d === 'left') return true;
                return false;
            };

            if (!isOpposite(dir) && !isNextOpposite(dir)) {
                this.nextDirection = dir;
            }
        },

        setFood(x, y) {
            this.foodPos = [x, y];
            this.draw();
        },

        generateFood() {
            let newX, newY;
            let collision;
            do {
                newX = Math.floor(Math.random() * this.w);
                newY = Math.floor(Math.random() * this.h);
                collision = this.snakeBody.some(seg => seg[0] === newX && seg ent[1] === newY);
            } while (collision);
            this.foodPos = [newX, newY];
        },

        snake() { return this.snakeBody; },
        food() { return this.foodPos; },
        alive() { return this.isAlive; },
        score() { return this.scoreValue; },

        draw() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw Food
            ctx.fillStyle = '#f44336';
            ctx.beginPath();
            ctx.arc((this.foodPos[0] * cellSize) + cellSize/2, (this.foodPos[1] * cellSize) + cellSize/2, cellSize/2.5, 0, Math.PI * 2);
            ctx.fill();

            // Draw Snake
            this.snakeBody.forEach((seg, index) => {
                ctx.fillStyle = index === 0 ? '#8bc34a' : '#4caf50';
                ctx.fillRect(seg[0] * cellSize + 1, seg[1] * cellSize + 1, cellSize - 2, cellSize - 2);
            });
        }
    };

    // Expose API to window for grading
    window.game = game;

    function updateScoreDisplay(val) {
        scoreEl.innerText = `Score: ${val}`;
    }

    // Input Handling
    window.addEventListener('keydown', (e) => {
        if (e.key === 'ArrowUp') game.setDir('up');
        else if (e.key === 'ArrowDown') game.setDir('down');
        else if (e.key === 'ArrowLeft') game.setDir('left');
        else if (e.key === 'ArrowRight') game.setDir('right');
    });

    // Button Handlers
    startBtn.addEventListener('click', () => {
        if (gameLoopId) return;
        if (!game.isAlive) game.reset();
        gameLoopId = setInterval(() => game.tick(), 150);
    });

    pauseBtn.addEventListener('click', () => {
        clearInterval(gameLoopId);
        gameLoopId = null;
    });

    resetBtn.addEventListener('click', () => {
        clearInterval(gameLoopId);
        gameLoopId = null;
        game.reset();
    });

    // Initial Draw
    game.reset();

})();
</script>
</body>
</html>
